    for (int p = 1; p < n - 3; ++p) {
        // Check nums[0..p] is strictly increasing
        bool increasing1 = true;
        for (int i = 1; i <= p; ++i) {
            if (nums[i] <= nums[i-1]) {
                increasing1 = false;
                break;
            }
        }
        if (!increasing1) continue;

        for (int q = p + 1; q < n - 1; ++q) {
            // Check nums[p..q] is strictly decreasing
            bool decreasing = true;
            for (int i = p + 1; i <= q; ++i) {
                if (nums[i] >= nums[i-1]) {
                    decreasing = false;
                    break;
